#!/usr/bin/env node
// patch-apk-icon.cjs — Icône APK native (launcher Android) = logo Trengo.
// Écrit les mipmaps ic_launcher / ic_launcher_round / ic_launcher_foreground (5 densités).
const fs=require('fs'); const path=require('path'); const ROOT=process.cwd();
let ok=0,fail=0;
function w(rel,b64){ try{ const p=path.join(ROOT,rel); fs.mkdirSync(path.dirname(p),{recursive:true}); fs.writeFileSync(p,Buffer.from(b64,'base64')); console.log('  \u2705 '+rel); ok++; }catch(e){ console.log('  \u274c '+rel+': '+e.message); fail++; } }

console.log('\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
console.log('  PATCH — Icône APK native (Trengo)');
console.log('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n');
if(!fs.existsSync(path.join(ROOT,'android'))){ console.log('  \u274c Dossier android/ introuvable dans ce repo.\n  Lance ce patch dans ~/Tsengo-fresh (où se trouve android/).'); process.exit(1); }
w('android/app/src/main/res/mipmap-mdpi/ic_launcher.png','');
w('android/app/src/main/res/mipmap-mdpi/ic_launcher_round.png','');
w('android/app/src/main/res/mipmap-mdpi/ic_launcher_foreground.png','');
w('android/app/src/main/res/mipmap-hdpi/ic_launcher.png','');
w('android/app/src/main/res/mipmap-hdpi/ic_launcher_round.png','');
w('android/app/src/main/res/mipmap-hdpi/ic_launcher_foreground.png','');
w('android/app/src/main/res/mipmap-xhdpi/ic_launcher.png','');
w('android/app/src/main/res/mipmap-xhdpi/ic_launcher_round.png','');
w('android/app/src/main/res/mipmap-xhdpi/ic_launcher_foreground.png','');
w('android/app/src/main/res/mipmap-xxhdpi/ic_launcher.png','');
w('android/app/src/main/res/mipmap-xxhdpi/ic_launcher_round.png','');
w('android/app/src/main/res/mipmap-xxhdpi/ic_launcher_foreground.png','');
w('android/app/src/main/res/mipmap-xxxhdpi/ic_launcher.png','');
w('android/app/src/main/res/mipmap-xxxhdpi/ic_launcher_round.png','');
w('android/app/src/main/res/mipmap-xxxhdpi/ic_launcher_foreground.png','');

console.log('\n  Résultat: '+ok+' \u2705   '+fail+' \u274c');
if(fail===0) console.log('\n\ud83c\udf89 Icônes remplacées. Reconstruis l\'APK pour voir le nouveau logo.\n');
